import React, { useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
  Filler
} from "chart.js";
import { Line, Bar } from "react-chartjs-2";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

const formatCurrency = (value) => {
  if (value == null) return "N/A";
  return `₹${Number(value).toLocaleString("en-IN")}`;
};

const formatNumber = (value, decimals = 2) => {
  if (value == null) return "N/A";
  return Number(value).toFixed(decimals);
};

const IndianStockDetails = () => {
  const [symbol, setSymbol] = useState("TCS.NS");
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchData = async () => {
    setError("");
    setLoading(true);
    setData(null);
    try {
      const res = await axios.get(`http://localhost:3000/api/stocks/${symbol}`);
      setData(res.data);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch stock data.");
    } finally {
      setLoading(false);
    }
  };

  const renderCharts = () => {
    if (!data?.historical?.quotes?.length) return null;

    const labels = data.historical.quotes.map(q =>
      new Date(q.date).toLocaleDateString("en-IN", {
        month: "short",
        day: "numeric"
      })
    );

    const closingPrices = data.historical.quotes.map(q => q.close);
    const volumes = data.historical.quotes.map(q => q.volume);

    return (
      <div style={{ display: "flex", gap: "40px", flexWrap: "wrap" }}>
        <div style={{ width: "600px" }}>
          <h4>📈 Closing Price</h4>
          <Line
            data={{
              labels,
              datasets: [
                {
                  label: `${data.symbol} Close`,
                  data: closingPrices,
                  borderColor: "#007bff",
                  backgroundColor: "rgba(0, 123, 255, 0.2)",
                  tension: 0.3,
                  fill: true
                }
              ]
            }}
            options={{
              responsive: true,
              plugins: { legend: { display: true } },
              scales: {
                y: {
                  ticks: {
                    callback: (v) => `₹${v}`
                  }
                }
              }
            }}
          />
        </div>

        <div style={{ width: "600px" }}>
          <h4>🔵 Volume Traded</h4>
          <Bar
            data={{
              labels,
              datasets: [
                {
                  label: "Volume",
                  data: volumes,
                  backgroundColor: "#28a745"
                }
              ]
            }}
            options={{
              responsive: true,
              plugins: { legend: { display: false } }
            }}
          />
        </div>
      </div>
    );
  };

  const renderTable = () => {
    if (!data?.historical?.quotes?.length) return null;

    return (
      <div style={{ marginTop: "20px" }}>
        <h4>📄 Daily OHLC Data</h4>
        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
            marginBottom: "20px",
            border: "1px solid #ddd"
          }}
        >
          <thead style={{ backgroundColor: "#007bff", color: "#fff" }}>
            <tr>
              <th>Date</th>
              <th>Open</th>
              <th>High</th>
              <th>Low</th>
              <th>Close</th>
              <th>Volume</th>
            </tr>
          </thead>
          <tbody>
            {data.historical.quotes.map((item, i) => (
              <tr key={i} style={{ background: i % 2 === 0 ? "#f9f9f9" : "#fff" }}>
                <td>{new Date(item.date).toLocaleDateString("en-IN")}</td>
                <td>{formatCurrency(item.open)}</td>
                <td>{formatCurrency(item.high)}</td>
                <td>{formatCurrency(item.low)}</td>
                <td>{formatCurrency(item.close)}</td>
                <td>{item.volume?.toLocaleString("en-IN")}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };

  const renderDividends = () => {
    const divs = data?.historical?.events?.dividends;
    if (!divs?.length) return <p>No dividend data available.</p>;

    return (
      <div style={{ marginTop: "20px" }}>
        <h4>💰 Dividends</h4>
        <table
          style={{
            width: "400px",
            borderCollapse: "collapse",
            marginBottom: "20px",
            border: "1px solid #ddd"
          }}
        >
          <thead style={{ backgroundColor: "#28a745", color: "#fff" }}>
            <tr>
              <th>Date</th>
              <th>Amount</th>
            </tr>
          </thead>
          <tbody>
            {divs.map((d, i) => (
              <tr key={i}>
                <td>{new Date(d.date * 1000).toLocaleDateString("en-IN")}</td>
                <td>{formatCurrency(d.amount)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  };

  return (
    <div style={{ padding: "20px", fontFamily: "Arial, sans-serif" }}>
      <h2>📊 Indian Stock Details</h2>
      <div style={{ marginBottom: "10px" }}>
        <input
          type="text"
          value={symbol}
          onChange={(e) => setSymbol(e.target.value)}
          placeholder="Enter Symbol (e.g. TCS.NS)"
          style={{
            padding: "8px",
            width: "250px",
            marginRight: "10px",
            borderRadius: "4px",
            border: "1px solid #ccc"
          }}
        />
        <button
          onClick={fetchData}
          disabled={loading}
          style={{
            padding: "8px 16px",
            backgroundColor: "#007bff",
            color: "#fff",
            border: "none",
            borderRadius: "4px",
            cursor: "pointer"
          }}
        >
          {loading ? "Loading..." : "Get Details"}
        </button>
      </div>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {data && (
        <>
          <h3>{data.name} ({data.symbol})</h3>
          <h1 style={{ color: data.change > 0 ? "green" : "red" }}>
            ₹{formatCurrency(data.price)} | Change: {formatNumber(data.change)} ({formatNumber(data.percentChange)}%)
          </h1>

          <ul style={{ lineHeight: "2em", fontSize: "16px" }}>
            <li><strong>Market Cap:</strong> {formatCurrency(data.marketCap)}</li>
            <li><strong>PE Ratio:</strong> {formatNumber(data.peRatio)}</li>
            <li><strong>52 Week High:</strong> {formatCurrency(data.fiftyTwoWeekHigh)}</li>
            <li><strong>52 Week Low:</strong> {formatCurrency(data.fiftyTwoWeekLow)}</li>
          </ul>

          {renderCharts()}
          {renderTable()}
          {renderDividends()}
        </>
      )}
    </div>
  );
};

export default IndianStockDetails;
